const rows = $input.all().map(i => i.json);
const assets = ["USD", "EUR", "GOLD", "NQ", "BTC"];
const pairs = [
  { instrument: "EUR/USD", base: "EUR" },
  { instrument: "XAU/USD", base: "GOLD" },
  { instrument: "BTC/USD", base: "BTC" },
  { instrument: "NQ/USD", base: "NQ" }
];
const LOW_CONVICTION_THRESHOLD = 60;

function parseMaybeJson(value, fallback = {}) {
  if (value === null || value === undefined || value === "") return fallback;
  if (typeof value === "object") return value;
  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function parseMaybeArray(value, fallback = []) {
  if (value === null || value === undefined || value === "") return fallback;
  if (Array.isArray(value)) return value;
  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed) ? parsed : fallback;
  } catch (e) {
    return [String(value)];
  }
}

function toNumber(value) {
  if (value === null || value === undefined || value === "") return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function clamp(value, min = 0, max = 100) {
  const n = toNumber(value);
  if (n === null) return null;
  return Math.max(min, Math.min(max, Math.round(n)));
}

function normalizeDirection(value) {
  const raw = String(value || "PENDING").trim().toUpperCase().replace(/\s+/g, "_");
  if (["PENDING", "NO_24H_CALL", "NO_CLEAR_BIAS", "NEUTRAL", "MARKET_CLOSED", ""].includes(raw)) return "NO_CLEAR_BIAS";
  if (raw.includes("BULLISH") || raw.includes("LONG")) return "BULLISH";
  if (raw.includes("BEARISH") || raw.includes("SHORT")) return "BEARISH";
  return "NO_CLEAR_BIAS";
}

function outputFromRow(row) {
  return parseMaybeJson(row.full_output, parseMaybeJson(row.raw_agent_output, {}));
}

function latestFor(agent) {
  return rows
    .filter(row => row.agent_name === agent && Number(row.layer) === 1)
    .filter(row => {
      const output = outputFromRow(row);
      const todayCall = output.today_call || {};
      return row.call_24h_direction || row.direction_24h || output.direction_24h || todayCall.direction;
    })
    .sort((a, b) => {
      const dateA = new Date(a.created_at || a.run_time_et || 0).getTime();
      const dateB = new Date(b.created_at || b.run_time_et || 0).getTime();
      return dateB - dateA;
    })[0] || null;
}

function assetCall(agent) {
  const row = latestFor(agent);
  if (!row) {
    return {
      agent,
      direction: "NO_CLEAR_BIAS",
      conviction: null,
      reason: "No usable Layer 1 24H output found.",
      warnings: ["Missing Layer 1 output"]
    };
  }

  const output = outputFromRow(row);
  const todayCall = output.today_call || {};

  return {
    agent,
    direction: normalizeDirection(todayCall.direction || row.call_24h_direction || row.direction_24h || output.direction_24h),
    conviction: clamp(todayCall.confidence ?? row.call_24h_conviction ?? row.conviction_24h ?? output.conviction_24h),
    reason: todayCall.executive_summary || row.call_24h_reason || output.reason_24h || row.reasoning_summary || output.reasoning_summary || "",
    warnings: [
      ...parseMaybeArray(row.warnings),
      ...parseMaybeArray(output.risk_flags),
      ...parseMaybeArray(output.warnings),
      ...parseMaybeArray(todayCall.invalidation_risks)
    ].filter(Boolean)
  };
}

const calls = Object.fromEntries(assets.map(asset => [asset, assetCall(asset)]));
const usd = calls.USD;
const trade_opportunities = [];
const avoid_today = [];

function avoid(instrument, reason) {
  avoid_today.push({ instrument, reason });
}

for (const pair of pairs) {
  const base = calls[pair.base];
  const confidence = clamp(((base.conviction ?? 0) + (usd.conviction ?? 0)) / 2);

  if (base.conviction === null || usd.conviction === null) {
    avoid(pair.instrument, "Missing 24H conviction from one or both Layer 1 assets.");
  } else if (base.direction === "NO_CLEAR_BIAS" || usd.direction === "NO_CLEAR_BIAS") {
    avoid(pair.instrument, "One or both assets have no clear 24H bias.");
  } else if (base.conviction < LOW_CONVICTION_THRESHOLD || usd.conviction < LOW_CONVICTION_THRESHOLD) {
    avoid(pair.instrument, "Mixed or low conviction 24H signals.");
  } else if (base.direction === usd.direction) {
    avoid(pair.instrument, "Both assets point in the same 24H direction, so there is no clear relative edge.");
  } else if (base.direction === "BULLISH" && usd.direction === "BEARISH") {
    trade_opportunities.push({
      instrument: pair.instrument,
      direction: "BUY",
      confidence,
      reason: `${pair.base} is independently bullish while USD is independently bearish during today's session.`
    });
  } else if (base.direction === "BEARISH" && usd.direction === "BULLISH") {
    trade_opportunities.push({
      instrument: pair.instrument,
      direction: "SELL",
      confidence,
      reason: `USD is independently bullish while ${pair.base} is independently bearish during today's session.`
    });
  } else {
    avoid(pair.instrument, "Mixed 24H signals.");
  }
}

trade_opportunities
  .sort((a, b) => b.confidence - a.confidence)
  .forEach((opportunity, index) => {
    opportunity.rank = index + 1;
  });

const dashboard = {
  dashboard_meta: {
    last_updated_et: new Date().toISOString(),
    source: "layer_2_trade_selection_agent"
  },
  trade_opportunities,
  avoid_today
};

return [
  {
    json: {
      file_content: JSON.stringify(dashboard, null, 2),
      dashboard
    }
  }
];

